changeSet.createView:
SELECT /* ── Identification du crédit ─────────────────────────────── */ c.IDCREDIT, c.NUMCREDIT, c.STATUT AS statut_credit, c.OBJET_CREDIT, c.CODE_OBJET_CREDIT, c.NUMEROCYCLE,
/* ── Membre emprunteur ───────────────────────────────────── */ m.NUM_MEMBRE, m.NOM AS nom_membre, m.PRENOM AS prenom_membre, m.SEXE,
/* ── Agence ──────────────────────────────────────────────── */ ag.CODE_AGENCE, ag.NOMAGENCE AS nom_agence,
/* ── Paramètres du crédit ─────────────────────────────────── */ c.DATE_DEBLOCAGE, c.DATE_ECHEANCE AS date_echeance_finale, c.DUREE, c.NOMBRE_ECHEANCE, c.PERIODICITE, c.TAUX_INTERET, c.TAUX_PENALITE, c.TAUX_COMMISSION, c.TAUX_ASSURANCE,
/* ── Montants ─────────────────────────────────────────────── */ c.MONTANT_ACCORDE, c.MONTANT_DEBLOQUER AS encours_brut, c.SOLDE_CAPITAL, c.SOLDE_INTERET, c.SOLDE_PENALITE,
/* ── Arriérés (agrégats des échéances en retard) ─────────── */ COALESCE(ret.nb_echeances_retard, 0) AS nb_echeances_retard, COALESCE(ret.capital_retard, 0) AS capital_retard, COALESCE(ret.interet_retard, 0) AS interet_retard, COALESCE(ret.penalite_retard, 0) AS penalite_retard, COALESCE(ret.assurance_retard, 0) AS assurance_retard, COALESCE(ret.commission_retard, 0) AS commission_retard, COALESCE(ret.taxe_retard, 0) AS taxe_retard,
/* ── Total arriérés (capital + intérêts + frais + taxes) ─── */ COALESCE(ret.capital_retard, 0) + COALESCE(ret.interet_retard, 0) + COALESCE(ret.penalite_retard, 0) + COALESCE(ret.assurance_retard,0) + COALESCE(ret.commission_retard,0) + COALESCE(ret.taxe_retard, 0) AS total_arrieres,
/* ── Délai de retard ──────────────────────────────────────── */ COALESCE(ret.max_jours_retard, 0) AS max_jours_retard, ret.date_premiere_echeance_retard,
/* ── Catégorie PAR (classification BCM) ──────────────────── */ /* SAIN = aucune échéance en retard */ /* PAR30 = 1 à 30 jours de retard */ /* PAR90 = 31 à 90 jours de retard */ /* PAR180 = 91 à 180 jours de retard */ /* PAR180+ = plus de 180 jours (créances douteuses) */ CASE WHEN COALESCE(ret.max_jours_retard, 0) = 0 THEN 'SAIN' WHEN COALESCE(ret.max_jours_retard, 0) <= 30 THEN 'PAR30' WHEN COALESCE(ret.max_jours_retard, 0) <= 90 THEN 'PAR90' WHEN COALESCE(ret.max_jours_retard, 0) <= 180 THEN 'PAR180' ELSE 'PAR180_PLUS' END AS categorie_par,
/* ── Taux PAR (encours à risque / encours total) ─────────── */ /* Calculé en proportion du solde capital restant dû */ CASE WHEN COALESCE(ret.max_jours_retard, 0) > 0 AND c.MONTANT_DEBLOQUER > 0 THEN CAST(c.SOLDE_CAPITAL AS FLOAT) / CAST(c.MONTANT_DEBLOQUER AS FLOAT) ELSE 0 END AS taux_par
FROM Credits c
LEFT JOIN membres m ON m.NUM_MEMBRE = c.nummembre
LEFT JOIN AGENCE ag ON ag.CODE_AGENCE = c.agence
/* ── Sous-requête : agrégation des échéances en retard ────────── */ LEFT JOIN ( SELECT ap.idcredit, COUNT(*) AS nb_echeances_retard, SUM(ap.CAPITAL - ap.CAPITAL_REMBOURSE) AS capital_retard, SUM(ap.INTERET - ap.INTERET_REMBOURSE) AS interet_retard, SUM(ap.PENALITE - ap.PENALITE_REGLEE) AS penalite_retard, SUM(ap.ASSURANCE - ap.ASSURANCE_REGLEE) AS assurance_retard, SUM(ap.COMMISSION - ap.COMMISSION_REGLEE) AS commission_retard, SUM(ap.TAXE - ap.TAXE_REGLEE) AS taxe_retard, MAX(DATEDIFF(day, ap.DATE_ECHEANCE, CAST(GETDATE() AS DATE))) AS max_jours_retard, MIN(ap.DATE_ECHEANCE) AS date_premiere_echeance_retard FROM Amortp ap WHERE ap.STATUT_ECHEANCE IN ('EN_RETARD', 'PARTIELLEMENT_REGLE') GROUP BY ap.idcredit ) ret ON ret.idcredit = c.IDCREDIT
WHERE c.STATUT = 'DEBLOQUE'
